const BeaconTrack={endpoints:[],defaultEvents:["click"],events:[],_lastSent:{},init(t={}){const e=t.endpoint||"/api/v1/stats/track/";this.endpoints=Array.isArray(e)?e:[e];this.events=t.events?[...this.defaultEvents,...t.events]:[...this.defaultEvents];this._bindClick();this.events.forEach(t=>this._bindEvent(t));this._bindPreInit()},track(t,e=null,n=0){const a=Date.now(),s=`${n}:${t}`;if(this._lastSent[s]&&a-this._lastSent[s]<300)return;this._lastSent[s]=a;const i=this.endpoints[n]??this.endpoints[0],o={event:t};null!==e&&(o.value=e);const c=new Blob([JSON.stringify(o)],{type:"application/json"});navigator.sendBeacon?navigator.sendBeacon(i,c):fetch(i,{method:"POST",body:c,keepalive:!0})},_getTrackData(t){return{key:t.dataset.track,value:t.dataset.trackValue||null,apiIndex:parseInt(t.dataset.api??"0",10)}},_bindClick(){document.addEventListener("click",t=>{const e=t.target.closest("[data-track]:not([data-track-on])");if(!e)return;const{key:n,value:a,apiIndex:s}=this._getTrackData(e);this.track(n,a,s)})},_bindEvent(t){document.addEventListener(t,e=>{const n=e.target.closest(`[data-track-on="${t}"]`);if(!n)return;const{key:a,value:s,apiIndex:i}=this._getTrackData(n);this.track(a,s,i)})},_bindPreInit(){document.querySelectorAll("[data-track-init]").forEach(t=>{const e=t.dataset.trackInitValue||null,n=parseInt(t.dataset.api??"0",10);this.track(t.dataset.trackInit,e,n)})}};
